import axios from "axios";
import { useEffect, useState } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [records, setRecords] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchRecords = async () => {
    try {
      const res = await axios.get("http://localhost:8000/records");
      setRecords(res.data.data || []);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => { fetchRecords(); }, []);

  const onFileChange = (e) => setFile(e.target.files[0]);

  const onSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setError("Please upload an image");
      return;
    }

    setLoading(true);
    setError("");

    const formData = new FormData();
    formData.append("image", file);

    try {
      const res = await axios.post("http://localhost:8000/classify", formData, {
        headers: { "Content-Type": "multipart/form-data" }
      });

      if (res.data?.success) {
        setResult(res.data.data);
        await fetchRecords();
      } else {
        setError("Unexpected API response");
      }
    } catch (err) {
      setError(err?.response?.data?.detail || err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 p-6">
      <div className="mx-auto max-w-3xl rounded-2xl bg-white px-8 py-10 shadow-xl">
        <h1 className="mb-6 text-center text-3xl font-bold text-gray-700">
          Cattle vs Buffalo Classifier
        </h1>

        <form onSubmit={onSubmit} className="space-y-4">
          <input
            type="file"
            accept="image/*"
            onChange={onFileChange}
            className="w-full rounded-md border border-gray-300 p-2"
          />
          <button
            type="submit"
            className="w-full rounded-md bg-indigo-600 px-4 py-2 font-semibold text-white hover:bg-indigo-700"
            disabled={loading}
          >
            {loading ? "Classifying..." : "Classify Image"}
          </button>
        </form>

        {error && <p className="mt-4 rounded-md bg-red-100 p-3 text-red-700">{error}</p>}

        {result && (
          <div className="mt-5 rounded-md border border-green-200 bg-green-50 p-4">
            <h2 className="text-xl font-bold text-green-800">Prediction:</h2>
            <p>Label: <strong>{result.label}</strong></p>
            <p>Confidence: <strong>{(result.confidence*100).toFixed(2)}%</strong></p>
            <p className="text-sm text-gray-600">File: {result.filename}</p>
          </div>
        )}

        <hr className="my-6 border-gray-200" />
        <h2 className="mb-4 text-xl font-semibold text-gray-700">Recent Records</h2>

        <div className="space-y-3">
          {records.length === 0 && <p className="text-gray-500">No records yet</p>}
          {records.map((item) => (
            <div key={item.id} className="rounded-lg border border-gray-200 p-3">
              <p className="font-medium">{item.label}</p>
              <p>Confidence: {(item.confidence * 100).toFixed(2)}%</p>
              <p className="text-sm text-gray-500">{new Date(item.timestamp).toLocaleString()} - {item.filename}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default App;
